Modified greedy insertion with fallback: evaluate all non-empty assigns plus one empty slot per order using a cost-aware score, attempt best feasible insertion, otherwise create a new assign if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	n := len(oris)
	assignCount := dispatch.AssignsLen
	fallbackLimit := assignCount
	for jj := 0; jj < n; jj++ {
		bestIdx := -1
		bestCostDelta := 1e18
		inserted := false
		candidates := make([]int, 0, assignCount+1)
		for ii := 0; ii < assignCount; ii++ {
			candidates = append(candidates, ii)
		}
		candidates = append(candidates, assignCount)
		for _, idx := range candidates {
			if idx == assignCount {
				if dispatch.Assigns[idx].StationsLen != 0 {
					continue
				}
			}
			ok := dispatch.Assigns[idx].AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				oldCost := dispatch.Assigns[idx].Cost
				dispatch.Assigns[idx].GenRoute()
				newCost := dispatch.Assigns[idx].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if delta < bestCostDelta {
						bestCostDelta = delta
						bestIdx = idx
					}
				}
			}
			dispatch.Assigns[idx].RemoveShip(total_ship + jj)
			if idx < assignCount && dispatch.Assigns[idx].StationsLen > 0 {
				dispatch.Assigns[idx].GenRoute()
			} else if idx < assignCount {
				dispatch.Assigns[idx].Cost = 0
			}
		}
		if bestIdx != -1 {
			ok := dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				dispatch.Assigns[bestIdx].GenRoute()
				if bestIdx >= assignCount {
					assignCount++
					dispatch.AssignsLen = assignCount
				}
				inserted = true
			}
		}
		if !inserted {
			for ee := fallbackLimit; ee < MAXASSIGNS; ee++ {
				ok := dispatch.Assigns[ee].AddShip(total_ship+jj, oris[jj], dess[jj])
				if ok {
					dispatch.Assigns[ee].GenRoute()
					if ee >= assignCount {
						assignCount = ee + 1
						dispatch.AssignsLen = assignCount
					}
					inserted = true
					break
				}
			}
			if !inserted && assignCount < MAXASSIGNS {
				idx := assignCount
				ok := dispatch.Assigns[idx].AddShip(total_ship+jj, oris[jj], dess[jj])
				if ok {
					dispatch.Assigns[idx].GenRoute()
					assignCount++
					dispatch.AssignsLen = assignCount
					inserted = true
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

